import React from 'react';
import './SponsorBar.css';

const sponsors = ['Vens Lures', 'Livingston Lures', 'Florida Fishing Products', 'Kalua II Boat'];

export default function SponsorBar() {
  return (
    <div className="sponsor-bar">
      <span className="sponsor-label">Endorsements & Gear</span>
      {/* Orvis Endorsed — first and most prominent per brief item #24 */}
      <span className="sponsor-pill sponsor-orvis">
        <span className="sponsor-orvis-mark">✓</span>
        Orvis Endorsed · 10 Years
      </span>
      <span className="sponsor-pill sponsor-uscg">U.S.C.G. Licensed Captain</span>
      {sponsors.map(s => <span className="sponsor-pill" key={s}>{s}</span>)}
    </div>
  );
}
